"use client";

import React, { useState } from "react";
import { Search, ChevronDown, Eye, Filter, CheckCircle, Clock } from "lucide-react";

// --- Mock Data for the Dashboard ---
const mockClaims = [
  {
    claimId: "C-0125",
    itemName: "Sports Watch (Digital)",
    itemId: "I-195",
    claimant: "user_115",
    dateSubmitted: "2025-12-05 10:30 AM",
    status: "Pending Review",
  },
  {
    claimId: "C-0124",
    itemName: "Blue Leather Backpack",
    itemId: "I-088",
    claimant: "user_201",
    dateSubmitted: "2025-12-04 03:15 PM",
    status: "Approved",
  },
  {
    claimId: "C-0123",
    itemName: "Car Keys (Ford)",
    itemId: "I-210",
    claimant: "user_090",
    dateSubmitted: "2025-12-03 11:00 AM",
    status: "Rejected",
  },
  {
    claimId: "C-0122",
    itemName: "Red Umbrella",
    itemId: "I-055",
    claimant: "user_305",
    dateSubmitted: "2025-12-03 09:45 AM",
    status: "Pending Review",
  },
];

const ClaimReviewDashboard = () => {
  const [claims, setClaims] = useState(mockClaims);
  const [searchTerm, setSearchTerm] = useState("");
  const [filterStatus, setFilterStatus] = useState("All");

  const getStatusClasses = (status) => {
    switch (status) {
      case "Pending Review":
        return "bg-yellow-100 text-yellow-800 border-yellow-300";
      case "Approved":
        return "bg-green-100 text-green-800 border-green-300";
      case "Rejected":
        return "bg-red-100 text-red-800 border-red-300";
      default:
        return "bg-gray-100 text-gray-800 border-gray-300";
    }
  };

  const handleViewDetails = (claimId) => {
    // In a real application, this would trigger navigation to the detailed review page:
    // router.push(`/admin/claims/${claimId}`);
    console.log(`Navigating to Claim Details for ID: ${claimId}`);
    alert(`Viewing details for Claim ID: ${claimId}`);
  };

  const filteredClaims = claims.filter((claim) => {
    const matchesSearch =
      claim.claimId.toLowerCase().includes(searchTerm.toLowerCase()) ||
      claim.itemName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      claim.claimant.toLowerCase().includes(searchTerm.toLowerCase());

    const matchesStatus =
      filterStatus === "All" || claim.status === filterStatus;

    return matchesSearch && matchesStatus;
  });

  return (
    <div className="min-h-screen bg-gray-50 p-8">
      <h1 className="text-3xl font-extrabold text-gray-900 border-b pb-3 mb-6">
        Claim Review Dashboard 📝
      </h1>

      {/* --- Filter and Search Controls --- */}
      <div className="flex flex-col md:flex-row gap-4 mb-6 p-4 bg-white rounded-lg shadow border">
        
        {/* Search Bar */}
        <div className="relative flex-grow">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-5 w-5 text-gray-400" />
          <input
            type="text"
            placeholder="Search by Claim ID, Item, or Claimant..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-indigo-500 focus:border-indigo-500"
          />
        </div>

        {/* Status Filter Dropdown */}
        <div className="relative w-full md:w-56">
          <Filter className="absolute left-3 top-1/2 transform -translate-y-1/2 h-5 w-5 text-gray-400" />
          <select
            value={filterStatus}
            onChange={(e) => setFilterStatus(e.target.value)}
            className="w-full pl-10 pr-8 py-2 border border-gray-300 rounded-lg appearance-none bg-white focus:ring-indigo-500 focus:border-indigo-500"
          >
            <option value="All">All Statuses</option>
            <option value="Pending Review">Pending Review</option>
            <option value="Approved">Approved</option>
            <option value="Rejected">Rejected</option>
          </select>
          <ChevronDown className="absolute right-3 top-1/2 transform -translate-y-1/2 h-5 w-5 text-gray-400 pointer-events-none" />
        </div>
      </div>

      {/* --- Claims Table --- */}
      <div className="bg-white shadow-lg rounded-xl overflow-hidden">
        <table className="min-w-full divide-y divide-gray-200">
          <thead className="bg-gray-100">
            <tr>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                Claim ID
              </th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                Item Name (ID)
              </th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                Claimant
              </th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                Date Submitted
              </th>
              <th className="px-6 py-3 text-center text-xs font-medium text-gray-500 uppercase tracking-wider">
                Status
              </th>
              <th className="relative px-6 py-3">
                <span className="sr-only">Actions</span>
              </th>
            </tr>
          </thead>
          <tbody className="bg-white divide-y divide-gray-200">
            {filteredClaims.length > 0 ? (
              filteredClaims.map((claim) => (
                <tr key={claim.claimId} className="hover:bg-indigo-50/50 transition duration-150">
                  <td className="px-6 py-4 whitespace-nowrap text-sm font-semibold text-indigo-600">
                    {claim.claimId}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                    {claim.itemName} <span className="text-xs text-gray-500">({claim.itemId})</span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-700">
                    {claim.claimant}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                    {claim.dateSubmitted}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span
                      className={`px-3 py-1 inline-flex text-xs leading-5 font-semibold rounded-full border ${getStatusClasses(claim.status)}`}
                    >
                       {claim.status === "Pending Review" && <Clock className="w-3 h-3 mr-1 mt-0.5" />}
                       {claim.status === "Approved" && <CheckCircle className="w-3 h-3 mr-1 mt-0.5" />}
                       {claim.status}
                    </span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                    {/* View Details Button */}
                    <button
                      onClick={() => handleViewDetails(claim.claimId)}
                      className="inline-flex items-center px-3 py-1.5 border border-transparent text-sm font-medium rounded-md shadow-sm text-white bg-indigo-600 hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 transition"
                    >
                      <Eye className="w-4 h-4 mr-1" />
                      View Claim
                    </button>
                  </td>
                </tr>
              ))
            ) : (
              <tr>
                <td colSpan="6" className="px-6 py-12 text-center text-gray-500 text-lg">
                  No claims match the current filters.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default ClaimReviewDashboard;